/// State machine for FileLock workflow
#[derive(Debug, Clone)]
pub struct FileLockStateMachine {
    current_state: FileLockState,
}

impl StateMachineBehavior for FileLockStateMachine {
    type State = FileLockState;
    type Transition = FileLockTransition;

    fn current_state(&self) -> FileLockState { self.current_state }
    fn set_current_state(&mut self, state: FileLockState) { self.current_state = state; }

    fn can_transition(&self, transition: FileLockTransition) -> bool {
        if matches!(self.current_state, FileLockState::Expired | FileLockState::Released) {
            return false;
        }

        match (self.current_state, transition) {
            (FileLockState::Active, FileLockTransition::Expire) => true,
            (FileLockState::Active, FileLockTransition::Release) => true,
            (FileLockState::Active, FileLockTransition::Refresh) => true,
            _ => false,
        }
    }
}

